#!/usr/bin/env python3
# -*- coding: utf-8 -*-
import os

OUT = os.path.dirname(os.path.abspath(__file__))

def write_module(name, data):
    lines = [f'{name} = {{']
    for k, (intro, one) in data.items():
        intro = intro.replace('\\', '\\\\').replace("'", "\\'")
        one = one.replace('\\', '\\\\').replace("'", "\\'")
        lines.append(f"    '{k}': {{'intro': '{intro}', 'one': '{one}'}},")
    lines.append('}')
    with open(os.path.join(OUT, f'writer_texts_{name.lower()}.py'), 'w', encoding='utf-8') as f:
        f.write('\n'.join(lines))
    print('wrote', name, len(data))

